import{_ as o,o as a,c as t,a2 as n}from"./chunks/framework.D5wUhsuj.js";const s="/docs/assets/opencode-spawner.DCrRoKqN.png",r="/docs/assets/opencode-ui-welcome.CTGgqEKH.png",i="/docs/assets/open-project-ui.DkL53Hyd.png",d="/docs/assets/create-ssh-key.CYRSfrok.png",l="/docs/assets/connect-provider.DpIq-tjN.png",p="/docs/assets/slash-commands.Ce7XAThi.png",c="/docs/assets/opencode-in-action-pathing.C5MUvPiu.png",h="/docs/assets/terminal-and-todo-ui.KQCahnZL.png",u="/docs/assets/add-mcp-servers.DY4vX9yO.png",m="/docs/assets/opencode-in-action-mcp.CmW-P-mB.png",O=JSON.parse('{"title":"OpenCode","description":"","frontmatter":{},"headers":[],"relativePath":"labs/opencode.md","filePath":"labs/opencode.md","lastUpdated":1783543014000}'),g={name:"labs/opencode.md"};function b(f,e,k,y,w,v){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="opencode" tabindex="-1">OpenCode <a class="header-anchor" href="#opencode" aria-label="Permalink to &quot;OpenCode&quot;">​</a></h1><p>OpenCode Labs run <a href="https://github.com/anomalyco/opencode" target="_blank" rel="noreferrer">OpenCode</a> inside a prokube workspace, so you can manage long-running agentic coding sessions from the browser without giving the agent access to your local machine.</p><p>Because sessions run in the workspace, you can leave tasks running overnight, switch between multiple projects and sessions, and review changes before they reach Git or your local checkout.</p><p>prokube uses the open-source <a href="https://github.com/prokube/pk-opencode-webui" target="_blank" rel="noreferrer">pk-opencode-webui project</a> to run OpenCode in Kubeflow Notebooks. prokube.ai open-sourced this prefix-aware Web UI and Notebook integration so OpenCode can be exposed correctly behind workspace URL prefixes such as Kubeflow Notebook routes. The integration adds the notebook image, URL-prefix handling, project picker, Git/SSH helpers, MCP management UI, Lab-specific defaults, and workspace integration needed for this deployment model.</p><div class="info custom-block"><p class="custom-block-title">OpenCode documentation</p><p>For OpenCode features that are not specific to prokube, use the upstream <a href="https://opencode.ai/docs/" target="_blank" rel="noreferrer">OpenCode documentation</a>. For the prokube wrapper and notebook integration, see <a href="https://github.com/prokube/pk-opencode-webui" target="_blank" rel="noreferrer"><code>pk-opencode-webui</code></a>.</p></div><h2 id="when-to-use-opencode-labs" tabindex="-1">When to Use OpenCode Labs <a class="header-anchor" href="#when-to-use-opencode-labs" aria-label="Permalink to &quot;When to Use OpenCode Labs&quot;">​</a></h2><p>Use OpenCode Labs for fully agentic engineering workflows where code is mostly written, changed, and reviewed by AI agents. OpenCode is a good fit when agents should work iteratively: inspect the repository, propose changes, run commands or tests, react to feedback, and continue across longer sessions inside the workspace rather than on your laptop.</p><p>Common uses include:</p><ul><li>editing notebooks, pipeline code, model-serving code, MCP servers, agents, and platform examples;</li><li>asking a coding agent to inspect a workspace-specific issue while it has access to the same mounted files and services;</li><li>working across several project directories from one browser session;</li><li>configuring or testing MCP servers while developing agent workflows;</li><li>reviewing file changes and terminal output before committing to Git.</li></ul><p>Use <a href="./vscode.html">VS Code</a> when you want a full IDE. Use <a href="./jupyterlab.html">JupyterLab</a> when notebooks and exploratory analysis are the main workflow. Use <a href="./../agentops/sandboxes.html">Agent Sandboxes</a> for API-controlled execution environments used by agents and applications.</p><p>You can also combine OpenCode with sandboxes through MCP. This is useful when you want OpenCode to plan, inspect, and orchestrate work from its Lab, but do not want it to execute untrusted code or shell commands directly in the OpenCode Lab pod. In that setup, OpenCode talks to an MCP server, and the MCP server runs the actual workload in an <a href="./../agentops/sandboxes.html">Agent Sandbox</a>: OpenCode for interaction, sandboxes for isolated execution.</p><h2 id="start-an-opencode-lab" tabindex="-1">Start an OpenCode Lab <a class="header-anchor" href="#start-an-opencode-lab" aria-label="Permalink to &quot;Start an OpenCode Lab&quot;">​</a></h2><p>Create an OpenCode Lab from the Labs page. The launch dialog uses the same core options as other Labs: name, compute resources, storage, configurations, and security options.</p><p><img src="'+s+'" alt="Launch OpenCode Lab" loading="lazy"></p><p>After the Lab starts, open it from the Labs table. The OpenCode UI is served from the Lab pod and connects to the OpenCode API server running in the same container.</p><p><img src="'+r+'" alt="OpenCode welcome screen" loading="lazy"></p><p>The Lab starts:</p><ul><li>the upstream <code>opencode serve</code> backend on an internal loopback port;</li><li>the prefix-aware web UI on the notebook port used by Kubeflow;</li><li>process supervision for both services;</li><li>persistent OpenCode configuration under <code>/home/jovyan</code>;</li><li>startup handling for SSH key permissions on the mounted home volume.</li></ul><p>OpenCode Labs use the same lifecycle and persistence model as other Labs. See <a href="./#managing-labs">Managing Labs</a> and <a href="./#persistence-and-package-installation">Persistence and Package Installation</a> for shared behavior.</p><h2 id="open-or-clone-a-project" tabindex="-1">Open or Clone a Project <a class="header-anchor" href="#open-or-clone-a-project" aria-label="Permalink to &quot;Open or Clone a Project&quot;">​</a></h2><p>On first open, choose a project directory or clone a Git repository. The project picker can browse the Lab filesystem, create folders, clone repositories, and reopen recent projects.</p><p><img src="'+i+'" alt="Open a project" loading="lazy"></p><p>Keep active work under the persistent home directory, usually <code>/home/jovyan</code>, or another mounted volume. Files written only to the container filesystem are lost when the Lab is recreated.</p><p>For private repositories, configure Git credentials first. The OpenCode image includes Git and an SSH helper in Settings. If no SSH key exists, the UI shows the <code>ssh-keygen -t ed25519</code> command. Open the integrated terminal with the terminal button in the bottom-left corner, run the command there, then return to Settings. The UI displays public keys found under <code>~/.ssh/*.pub</code> so you can add them to GitHub, GitLab, or another Git host.</p><p><img src="'+d+'" alt="Create an SSH key" loading="lazy"></p><h2 id="connect-a-model-provider" tabindex="-1">Connect a Model Provider <a class="header-anchor" href="#connect-a-model-provider" aria-label="Permalink to &quot;Connect a Model Provider&quot;">​</a></h2><p>OpenCode needs a model provider before it can answer prompts or edit code. Use Settings to connect a provider such as OpenCode, Anthropic, GitHub Copilot, OpenAI, Google, or OpenRouter, depending on what your environment allows. You can also use models hosted on prokube itself, or external models that an administrator exposes through the <a href="./../agentops/agent_gateway.html">Agent Gateway</a>.</p><p><img src="'+l+'" alt="Connect a provider" loading="lazy"></p><p>Provider credentials are stored in the Lab environment according to OpenCode&#39;s configuration behavior. Treat them as workspace-scoped credentials: use narrowly scoped keys, avoid personal or administrator credentials, and rotate or remove keys when they are no longer needed.</p><h2 id="work-with-projects-and-sessions" tabindex="-1">Work with Projects and Sessions <a class="header-anchor" href="#work-with-projects-and-sessions" aria-label="Permalink to &quot;Work with Projects and Sessions&quot;">​</a></h2><p>In OpenCode, a project is the directory OpenCode works in. In practice this is usually a cloned Git repository or a folder under the persistent Lab home directory. The project defines the files, instructions, Git state, and working directory that OpenCode can inspect or modify.</p><p>A session is a single agent conversation attached to a project. You can keep multiple sessions for the same project, for example one for debugging, one for a refactor, and one for documentation. You can also switch between projects without restarting the Lab.</p><p>Within a session, you can switch model/provider settings, attach files, fork from earlier messages, and let OpenCode request permissions before file edits or shell commands.</p><p>The UI also exposes features from the prokube wrapper around the OpenCode backend:</p><ul><li>project-aware sessions and recent projects;</li><li>saved prompts available globally or per project;</li><li>editable instruction files such as <code>AGENTS.md</code>;</li><li>command palette and keyboard hint mode;</li><li>file tree, file viewer, diffs, and image attachments;</li><li>session timeline rendering for tool calls and agent activity.</li></ul><p><img src="'+p+'" alt="Slash commands and pickers" loading="lazy"></p><p><img src="'+c+'" alt="OpenCode in action" loading="lazy"></p><h2 id="control-permissions-and-execution" tabindex="-1">Control Permissions and Execution <a class="header-anchor" href="#control-permissions-and-execution" aria-label="Permalink to &quot;Control Permissions and Execution&quot;">​</a></h2><p>OpenCode can make real changes to files and run commands in the Lab container. If you use it in a workspace with sensitive code, data, credentials, or platform access, prokube recommends starting with narrow permissions and expanding them only when needed.</p><p>During Lab launch, set the OpenCode security settings explicitly instead of accepting broad access by habit. These settings are the first control surface for what the Lab can access and what OpenCode is allowed to do. If those launch-time controls are not enough for your workflow or risk model, tighten OpenCode itself through its config file.</p><p>In the prokube OpenCode image, the global OpenCode config is stored at:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/home/jovyan/.config/opencode/opencode.json</span></span></code></pre></div><p>This path is under the persistent Lab home directory. The image provides a default config at that location, and startup scripts create the config directory without overwriting an existing config on the mounted home volume.</p><p>Useful upstream OpenCode references:</p><ul><li><a href="https://opencode.ai/docs/config/" target="_blank" rel="noreferrer">Configuration</a></li><li><a href="https://opencode.ai/docs/permissions/" target="_blank" rel="noreferrer">Permissions</a></li><li><a href="https://opencode.ai/docs/tools/" target="_blank" rel="noreferrer">Tools</a></li><li><a href="https://opencode.ai/docs/mcp-servers/" target="_blank" rel="noreferrer">MCP servers</a></li></ul><p>OpenCode permissions are configured in <code>opencode.json</code>. Defaults can be permissive depending on the tool and environment, so explicitly set sensitive tools to <code>ask</code> or <code>deny</code> when you want review before edits, shell commands, task delegation, or MCP tool calls. OpenCode also supports tool patterns and MCP-tool wildcards; use those to allow only the operations a project actually needs.</p><p>For coding-agent workflows, prokube disables broad Kubernetes and object-storage access by default where possible, and recommends granting only the narrow permissions required for the task. Do not assume <code>kubectl</code> access or S3-compatible object storage credentials are available in an OpenCode Lab.</p><p>The OpenCode image is not intended for local container image builds and does not include the Docker/Buildx workflow used by some other Labs.</p><p>For stronger isolation, do not rely on a &quot;read-only directory&quot; convention as the main security boundary. Upstream OpenCode documents <a href="https://opencode.ai/docs/references/" target="_blank" rel="noreferrer">references</a> for adding external context, and read-only external directory behavior has been discussed upstream, for example in <a href="https://github.com/anomalyco/opencode/issues/18441" target="_blank" rel="noreferrer">anomalyco/opencode#18441</a>. For real isolation, deny invasive OpenCode tools and avoid mounting sensitive directories or credentials into the OpenCode Lab in the first place.</p><p>If OpenCode should only inspect or orchestrate work, run edits, tests, and command execution through an MCP server backed by an <a href="./../agentops/sandboxes.html">Agent Sandbox</a>. In that setup, the OpenCode Lab is the interactive interface and the sandbox is the execution boundary.</p><h2 id="use-the-integrated-terminal" tabindex="-1">Use the Integrated Terminal <a class="header-anchor" href="#use-the-integrated-terminal" aria-label="Permalink to &quot;Use the Integrated Terminal&quot;">​</a></h2><p>OpenCode Labs include an integrated terminal backed by the OpenCode PTY API. Use it for normal development commands such as <code>git</code>, SSH setup, package managers, tests, and CLIs that are available in the selected image.</p><p><img src="'+h+'" alt="Integrated terminal" loading="lazy"></p><p>The terminal runs inside the same Lab pod as OpenCode. It is useful for explicit manual commands, but it is not a separate sandbox. If you need package installation patterns or object-storage access in a Lab where those permissions are intentionally enabled, use the shared Labs guidance:</p><ul><li><a href="./../platform/object_storage.html">Object Storage</a></li><li><a href="./#persistence-and-package-installation">Persistence and Package Installation</a></li></ul><h2 id="add-mcp-servers" tabindex="-1">Add MCP Servers <a class="header-anchor" href="#add-mcp-servers" aria-label="Permalink to &quot;Add MCP Servers&quot;">​</a></h2><p>OpenCode supports <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol</a> servers. The prokube UI provides a graphical MCP manager for adding remote servers, connecting and disconnecting them, starting OAuth flows where supported, and seeing server status.</p><p><img src="'+u+'" alt="Add MCP servers" loading="lazy"></p><p>Remote MCP entries can include a URL, optional Authorization header, custom HTTP headers, timeout, and OAuth settings. The UI writes MCP configuration through OpenCode&#39;s config APIs.</p><p><img src="'+m+'" alt="OpenCode with MCP" loading="lazy"></p><p>For hosting MCP servers on prokube, platform-managed MCP endpoints, and public routing, see <a href="./../agentops/mcp_servers.html">MCP Servers</a>. For memory-backed MCP endpoints, see <a href="./../agentops/memory_stores.html">Memory Stores</a>.</p><h2 id="relationship-to-agent-sandboxes" tabindex="-1">Relationship to Agent Sandboxes <a class="header-anchor" href="#relationship-to-agent-sandboxes" aria-label="Permalink to &quot;Relationship to Agent Sandboxes&quot;">​</a></h2><p>OpenCode Labs are interactive development environments for humans working with a coding agent. They are long-lived enough for development, inspection, and review, but they are still Labs: storage and lifecycle follow the Lab model.</p><p><a href="./../agentops/sandboxes.html">Agent Sandboxes</a> are API-managed execution environments for agents and applications. They can be created, claimed, paused, resumed, and controlled through APIs. Use OpenCode Labs to build and debug the code, then move operational agent execution into sandboxes or dedicated services when the workflow becomes repeatable.</p><h2 id="operational-notes" tabindex="-1">Operational Notes <a class="header-anchor" href="#operational-notes" aria-label="Permalink to &quot;Operational Notes&quot;">​</a></h2><p>OpenCode Labs run as workspace pods. They inherit the same workspace access model, storage behavior, and operational limits as other Labs.</p><p>Important points:</p><ul><li>Persist work under <code>/home/jovyan</code> or another mounted volume.</li><li>Stop or delete unused Labs to release compute resources.</li><li>Keep provider keys and Git credentials scoped to the workspace risk level.</li><li>Browser-based agent activity may not behave like a Jupyter kernel for every idle-culling setup; confirm automatic shutdown behavior in your environment.</li><li>If the UI opens but the agent does not respond, check provider configuration and OpenCode logs in the Lab home directory.</li></ul><p>For general lifecycle issues, storage attachment problems, image pull errors, and pod-level debugging, see <a href="./#troubleshooting-labs">Troubleshooting Labs</a>.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./">Using Labs</a></li><li><a href="./vscode.html">VS Code</a></li><li><a href="./jupyterlab.html">JupyterLab</a></li><li><a href="./../agentops/sandboxes.html">Agent Sandboxes</a></li><li><a href="./../agentops/mcp_servers.html">MCP Servers</a></li><li><a href="https://github.com/prokube/pk-opencode-webui" target="_blank" rel="noreferrer">pk-opencode-webui on GitHub</a></li><li><a href="https://github.com/anomalyco/opencode" target="_blank" rel="noreferrer">OpenCode upstream project</a></li></ul>',71)])])}const x=o(g,[["render",b]]);export{O as __pageData,x as default};
